const { execSync } = require('child_process');
const cmd = params.command || 'ps';
const allowed = ['ps', 'logs', 'images', 'inspect', 'stats', 'version', 'info'];
const base = cmd.split(' ')[0];
if (!allowed.includes(base)) {
  throw new Error('Docker command not allowed: ' + base);
}
const result = execSync('docker ' + cmd, { encoding: 'utf-8', timeout: 30000 });
return { output: result };
